const leads = $input.first().json.data || [];
const now = new Date();
const weekAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);
const thisWeek = leads.filter(l => new Date(l.Created_Time) >= weekAgo);
const qualified = thisWeek.filter(l => l.Lead_Status === "Qualified");
const converted = thisWeek.filter(l => l.Lead_Status === "Converted");
const sources = thisWeek.reduce((acc, l) => { acc[l.Lead_Source || "Unknown"] = (acc[l.Lead_Source || "Unknown"] || 0) + 1; return acc; }, {});
const topSource = Object.entries(sources).sort((a,b)=>b[1]-a[1])[0] || ["N/A", 0];
return [{ json: {
  reportDate: now.toISOString().split("T")[0],
  clientName: "${CLIENT_NAME}",
  clientId: "${CLIENT_ID}",
  budget: "${BUDGET}",
  metrics: {
    totalLeads: thisWeek.length,
    qualifiedLeads: qualified.length,
    convertedLeads: converted.length,
    qualificationRate: thisWeek.length > 0 ? ((qualified.length / thisWeek.length) * 100).toFixed(1) + "%" : "0%",
    conversionRate: thisWeek.length > 0 ? ((converted.length / thisWeek.length) * 100).toFixed(1) + "%" : "0%",
    topLeadSource: topSource[0],
    topSourceCount: topSource[1]
  },
  sourceBreakdown: sources
} }];

const d = $input.first().json;
const m = d.metrics;
const rows = [
  ["Total Leads", m.totalLeads],
  ["Leads Calificados", m.qualifiedLeads],
  ["Leads Convertidos", m.convertedLeads],
  ["Tasa Calificacion", m.qualificationRate],
  ["Tasa Conversion", m.conversionRate],
  ["Fuente Principal", m.topLeadSource + " (" + m.topSourceCount + ")"]
].map((r, i) => `<tr style="background:${i%2===0?"#f8fafc":"#fff"}"><td style="padding:10px;border-bottom:1px solid #e2e8f0">${r[0]}</td><td style="padding:10px;border-bottom:1px solid #e2e8f0">${r[1]}</td></tr>`).join("");
const html = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto"><h1 style="color:#0891b2">Reporte Semanal — ${d.clientName}</h1><p style="color:#64748b">Semana del ${d.reportDate}</p><table style="width:100%;border-collapse:collapse;margin:20px 0"><tr style="background:#f1f5f9"><td style="padding:12px;font-weight:bold">Metrica</td><td style="padding:12px;font-weight:bold">Valor</td></tr>${rows}</table><p style="color:#64748b;font-size:12px">Generado por ai50m.com para ${d.clientName}</p></div>`;
return [{ json: { ...d, reportHtml: html } }];
